import style from './Portofolio.module.css'
import { Link } from 'react-router-dom';

function Portofolio() {

    const projects = [
        {
            id: 1,
            title: "Web Design Project",
            description: "Modern and responsive web design for a company profile.",
            image: "/image/potofolio/smp.jpg",
        },
        {
            id: 2,
            title: "E-Commerce App",
            description: "Full-stack online store with React and Node.js.",
            image: "/image/potofolio/smk.jpg",
        },
        {
            id: 3,
            title: "Landing Page",
            description: "Creative landing page for a startup.",
            image: "/image/potofolio/training.jpg",
        },
    ];

    return (
        <div className={style.portofoliopage}>
            <header className={style.header}>
                <h1 className={style.logo}>MSHDQ</h1>
                <nav className={style.nav}>
                    <Link to="/" className={style.link}>HOME</Link>
                    <Link to="/about" className={style.link}>ABOUT</Link>
                    <Link to="/service" className={style.link}>SERVICE</Link>
                    <Link to="/portofolio" className={style.link}>PORTOFOLIO</Link>
                    <Link to="/blog" className={style.link}>BLOG</Link>
                    <Link to="/contact" className={style.link}>CONTACT</Link>
                </nav>
            </header>

            <div className={style.portofolio}>
                <h1 className={style.portofolio_title}>My Portfolio</h1>
                <p className={style.portofolio_subtitle}>
                    Some of my recent works in web design and development.
                </p>

                <div className={style.portfolio_grid}>
                    {projects.map((projects) => (
                        <div className={style.portofolio_card} key={project.id}>
                            <img
                                src={project.image}
                                alt={project.title}
                                className={style.portfolio_image}
                            />
                            <h2 className={style.portofolio_card_title}>{project.title}</h2>
                            <p className={style.portofolio_card_subtitle}>{project.description}</p>
                        </div>
                    ))}
                </div>
            </div>

        </div>
    )
}

export default Portofolio;
